/**
 * Base event system types for NMI components
 * Component-specific event types should be defined in their respective packages
 */
export interface EventMetadata {
    component: string;
    componentVersion: string;
    timestamp: number;
}
export interface NmiCustomEvent<T = any> extends CustomEvent {
    detail: {
        data: T;
        meta: EventMetadata;
    };
}
export interface ReportingError {
    type: 'auth' | 'network' | 'validation' | 'unknown';
    message: string;
    code?: string;
}
